class MetadataManager:
    def __init__(self):
        self.metadata = {
            'tables': {},
            'columns': {},
            'lineage': []
        }

    def extract_table_metadata(self, table_name, connection):
        """Extract metadata for a table"""
        cursor = connection.cursor()

        # Get column information
        cursor.execute(f"SELECT * FROM {table_name} WHERE 1=0")
        columns = cursor.description

        table_metadata = {
            'name': table_name,
            'column_count': len(columns),
            'columns': []
        }

        for col in columns:
            column_info = {
                'name': col[0],
                'type': col[1],
                'size': col[3],
                'nullable': col[6]
            }
            table_metadata['columns'].append(column_info)

        self.metadata['tables'][table_name] = table_metadata
        return table_metadata

    def track_data_lineage(self, source_table, target_table, transformation):
        """Track data lineage"""
        lineage_entry = {
            'source': source_table,
            'target': target_table,
            'transformation': transformation,
            'timestamp': datetime.now()
        }
        self.metadata['lineage'].append(lineage_entry)

# Example usage
manager = MetadataManager()
table_meta = manager.extract_table_metadata('sales_fact', db_connection)
print(f"Extracted metadata for table: {table_meta['name']}")
print(f"Columns: {table_meta['column_count']}")

import java.sql.*;
import java.util.concurrent.*;

public class DWConnectionPool {
    private static final int MAX_POOL_SIZE = 20;
    private static final int MIN_IDLE = 5;
    private BlockingQueue<Connection> availableConnections;
    private BlockingQueue<Connection> usedConnections;

    public DWConnectionPool(String url, String user, String password) 
        throws SQLException {
        availableConnections = new LinkedBlockingQueue<>();
        usedConnections = new LinkedBlockingQueue<>();

        // Initialize minimum idle connections
        for (int i = 0; i < MIN_IDLE; i++) {
            availableConnections.add(createConnection(url, user, password));
        }
    }

    private Connection createConnection(String url, String user, String password) 
        throws SQLException {
        Connection conn = DriverManager.getConnection(url, user, password);
        // Set warehouse-optimized properties
        conn.setAutoCommit(false);
        conn.setTransactionIsolation(Connection.TRANSACTION_READ_COMMITTED);
        return conn;
    }

    public Connection getConnection() throws SQLException {
        Connection conn = availableConnections.poll(30, TimeUnit.SECONDS);
        if (conn == null) {
            throw new SQLException("Connection timeout");
        }
        usedConnections.offer(conn);
        return conn;
    }

    public void releaseConnection(Connection conn) {
        usedConnections.remove(conn);
        availableConnections.offer(conn);
    }

    // Execute query with automatic connection management
    public ResultSet executeQuery(String query) throws SQLException {
        Connection conn = getConnection();
        try {
            Statement stmt = conn.createStatement();
            stmt.setQueryTimeout(300); // 5 minute timeout for warehouse queries
            return stmt.executeQuery(query);
        } finally {
            releaseConnection(conn);
        }
    }
}
